func resolveSourceProbeCandidates(group string, urls []string) ([]sourceProbeCandidate, error) {
	group = strings.TrimSpace(strings.ToLower(group))
	if group == "" {
		group = "appliance-showrooms"
	}
	var candidates []sourceProbeCandidate
	switch group {
	case "none":
	case "all":
		for _, name := range []string{"appliance-showrooms", "appliance-priority-gaps", "bath-showrooms", "bath-priority-gaps"} {
			candidates = append(candidates, sourceProbeCandidateGroups[name]...)
		}
	default:
		groupCandidates, ok := sourceProbeCandidateGroups[group]
		if !ok {
			return nil, fmt.Errorf("unknown source-probe candidate group %q", group)
		}
		candidates = append(candidates, groupCandidates...)
	}
	for _, rawURL := range urls {
		rawURL = strings.TrimSpace(rawURL)
		if rawURL == "" {
			continue
		}
		candidates = append(candidates, sourceProbeCandidate{Label: rawURL, URL: rawURL, Group: "custom"})
	}
	if len(candidates) == 0 {
		return nil, fmt.Errorf("no source-probe candidates selected")
	}
	return candidates, nil
}

